mapper.update:
UPDATE bm_barcode_detail
SET qty = #{qty}
WHERE barcode = #{barcode}

mapper.select:
SELECT
    MAX(CAST(SUBSTRING(barcode, CHARINDEX('#', barcode, LEN(barcode) - CHARINDEX('#', REVERSE(barcode)) + 1) + 1, LEN(barcode)) AS INT)) AS maxLabelSeq
FROM bm_barcode_detail
WHERE item_no = #{itemNo}
  AND lot_date = #{date,jdbcType=DATE}
